class TestHookIngestion:
    def test_hook_writes_log_row(self, client, db) -> None:
        with patch(
            "agentpulse.platforms.claude.hooks.detect_entrypoint",
            return_value="vscode",
        ):
            resp = client.post("/hooks/claude", json=_SAMPLE_HOOK)
        assert resp.status_code == 200

        cursor = run_async(
            db.execute(
                "SELECT * FROM claude_log_hooks WHERE session_id = ?",
                ("s-1",),
            )
        )
        rows = run_async(cursor.fetchall())
        assert len(rows) == 1
        row = dict(rows[0])
        assert row["pid"] == 4242
        assert row["source_system"] == "host.example"
        assert row["cwd"] == "/proj"
        assert row["event_name"] == "PreToolUse"
        assert row["tool_name"] == "Bash"
        assert row["agent_id"] is None
        assert row["entrypoint"] == "vscode"
        assert row["received_by"] == "hook-endpoint"

    def test_hook_raw_payload_preserves_wire_bytes(self, client, db) -> None:
        """Pydantic defaults must not leak into stored raw_payload."""
        minimal = {
            "session_id": "s-min",
            "hook_event_name": "Stop",
            "pid": 7,
        }
        client.post("/hooks/claude", json=minimal)

        cursor = run_async(
            db.execute(
                "SELECT raw_payload FROM claude_log_hooks WHERE session_id = ?",
                ("s-min",),
            )
        )
        row = dict(run_async(cursor.fetchone()))
        stored = json.loads(row["raw_payload"])
        assert set(stored.keys()) == {"session_id", "hook_event_name", "pid"}

    def test_hook_skips_log_row_when_no_pid(self, client, db) -> None:
        no_pid = {
            "session_id": "s-no-pid",
            "hook_event_name": "PreToolUse",
            "tool_name": "Bash",
        }
        with patch(
            "agentpulse.platforms.claude.hooks.detect_entrypoint",
            return_value="cli",
        ):
            resp = client.post("/hooks/claude", json=no_pid)
        assert resp.status_code == 200

        cursor = run_async(
            db.execute(
                "SELECT count(*) AS n FROM claude_log_hooks WHERE session_id = ?",
                ("s-no-pid",),
            )
        )
        assert dict(run_async(cursor.fetchone()))["n"] == 0

    def test_multiple_hooks_append(self, client, db) -> None:
        for event in ("PreToolUse", "PostToolUse", "Stop"):
            payload = {**_SAMPLE_HOOK, "hook_event_name": event}
            client.post("/hooks/claude", json=payload)

        cursor = run_async(
            db.execute(
                "SELECT event_name FROM claude_log_hooks "
                "WHERE session_id = ? ORDER BY id",
                ("s-1",),
            )
        )
        rows = run_async(cursor.fetchall())
        assert [dict(r)["event_name"] for r in rows] == [
            "PreToolUse",
            "PostToolUse",
            "Stop",
        ]

    def test_invalid_payload_returns_422(self, client) -> None:
        resp = client.post(
            "/hooks/claude",
            json={"not_a_valid": "payload"},
        )
        assert resp.status_code == 422


class TestStatuslineIngestion:
    def test_statusline_writes_log_row(self, client, db) -> None:
        resp = client.post("/statusline/claude", json=_SAMPLE_STATUSLINE)
        assert resp.status_code == 200

        cursor = run_async(
            db.execute(
                "SELECT * FROM claude_log_statuslines WHERE session_id = ?",
                ("s-1",),
            )
        )
        rows = run_async(cursor.fetchall())
        assert len(rows) == 1
        row = dict(rows[0])
        assert row["pid"] == 4242
        assert row["source_system"] == "host.example"
        assert row["cwd"] == "/proj"
        assert row["project_dir"] == "/proj"
        assert row["model_id"] == "claude-opus-4-7[1m]"
        assert row["model_name"] == "Opus 4.7 (1M context)"
        assert row["claude_version"] == "2.1.117"
        assert row["cost_usd"] == 1.25
        assert row["duration_seconds"] == 60.0
        assert row["api_duration_seconds"] == 12.0
        assert row["context_used_pct"] == 25.0
        assert row["cache_read_tokens"] == 800
        assert row["cache_creation_tokens"] == 300
        assert row["received_by"] == "statusline-endpoint"

    def test_statusline_raw_payload_preserves_wire_bytes(self, client, db) -> None:
        client.post("/statusline/claude", json=_SAMPLE_STATUSLINE)

        cursor = run_async(
            db.execute(
                "SELECT raw_payload FROM claude_log_statuslines "
                "WHERE session_id = ?",
                ("s-1",),
            )
        )
        row = dict(run_async(cursor.fetchone()))
        stored = json.loads(row["raw_payload"])
        assert stored == _SAMPLE_STATUSLINE

    def test_statusline_skips_log_row_when_no_pid(self, client, db) -> None:
        no_pid = {k: v for k, v in _SAMPLE_STATUSLINE.items() if k != "pid"}
        client.post("/statusline/claude", json=no_pid)

        cursor = run_async(
            db.execute(
                "SELECT count(*) AS n FROM claude_log_statuslines "
                "WHERE session_id = ?",
                ("s-1",),
            )
        )
        assert dict(run_async(cursor.fetchone()))["n"] == 0

    def test_statusline_ignored_no_session_id(self, client, db) -> None:
        no_sid = {k: v for k, v in _SAMPLE_STATUSLINE.items() if k != "session_id"}
        resp = client.post("/statusline/claude", json=no_sid)
        assert resp.json()["status"] == "ignored"

        cursor = run_async(
            db.execute("SELECT count(*) AS n FROM claude_log_statuslines")
        )
        assert dict(run_async(cursor.fetchone()))["n"] == 0

    def test_multiple_statuslines_append(self, client, db) -> None:
        for cost in (1.0, 2.0, 3.0):
            payload = {
                **_SAMPLE_STATUSLINE,
                "cost": {**_SAMPLE_STATUSLINE["cost"], "total_cost_usd": cost},
            }
            client.post("/statusline/claude", json=payload)

        cursor = run_async(
            db.execute(
                "SELECT cost_usd FROM claude_log_statuslines "
                "WHERE session_id = ? ORDER BY id",
                ("s-1",),
            )
        )
        rows = run_async(cursor.fetchall())
        assert [dict(r)["cost_usd"] for r in rows] == [1.0, 2.0, 3.0]
